```class Solution {
public:
    vector<vector<string>> findDuplicate(vector<string>& paths) {
        unordered_map<string, vector<string>> mp;
        for (string path : paths) {
            stringstream ss(path);
            string dir, file;
            while (getline(ss, dir, ' ')) {
                if (dir.empty()) break;
                string file_path;
                getline(ss, file);
                int start = file.find('(');
                int end = file.find(')');
                file_path = dir + "/" + file.substr(0, start) + "." + file.substr(start + 1, end - start - 1) + file.substr(end + 1);
                mp[file_path].push_back(path);
            }
        }
        vector<vector<string>> res;
        for (auto& p : mp) {
            if (p.second.size() > 1) res.push_back(p.second);
        }
        return res;
    }
};```
